#!/usr/bin/env python3
"""Block `pnpm test` (interactive watcher); steer Claude to `pnpm test:ci`."""
import json, sys

def main():
    try:
        ev = json.load(sys.stdin)
    except Exception:
        return 0
    if ev.get("tool_name") != "Bash":
        return 0
    inp = ev.get("tool_input") or {}
    cmd = inp.get("command", "")
    # Block bare `pnpm test` but allow `pnpm test:ci` or other test:* variants
    if cmd.strip().startswith("pnpm test") and " test:" not in cmd:
        print("Use `pnpm test:ci` instead — `pnpm test` opens an interactive watcher and won't return.", file=sys.stderr)
        return 2
    return 0

if __name__ == "__main__":
    sys.exit(main())

#!/usr/bin/env python3
"""After git commit operations, run pnpm lint and surface failures."""
import json, subprocess, sys

def main():
    try:
        ev = json.load(sys.stdin)
    except Exception:
        return 0
    if ev.get("tool_name") != "Bash":
        return 0
    inp = ev.get("tool_input") or {}
    cmd = inp.get("command", "")

    # Trigger on git commit commands (but not --amend without changes)
    if "git commit" not in cmd:
        return 0

    # Run pnpm lint
    try:
        result = subprocess.run(
            ["pnpm", "lint"],
            capture_output=True,
            text=True,
            timeout=30,
            cwd=ev.get("cwd", ".")
        )
        if result.returncode != 0:
            print("REQUIRED FOLLOW-UP: pnpm lint failed. Fix each error before proceeding:", file=sys.stderr)
            print(result.stdout, file=sys.stderr)
            print(result.stderr, file=sys.stderr)
            print("Do not stop until lint passes. Do not ask.", file=sys.stderr)
            return 2
    except Exception as e:
        # Don't block on errors running lint itself
        pass

    return 0

if __name__ == "__main__":
    sys.exit(main())

import json, sys, subprocess, re

def main():
    try:
        ev = json.load(sys.stdin)
    except Exception:
        return 0

    tool = ev.get("tool_name", "")
    inp = ev.get("tool_input") or {}
    resp = ev.get("tool_response") or {}

    if tool != "Edit":
        return 0

    file_path = inp.get("file_path", "")
    if not file_path.endswith(".py"):
        return 0

    # Read the edited file
    try:
        with open(file_path, 'r') as f:
            content = f.read()
    except Exception:
        return 0

    # Detect recursive function definitions
    # Pattern: def foo(...): ... foo(...)
    func_defs = re.findall(r'^def\s+(\w+)\s*\(', content, re.MULTILINE)

    for func_name in func_defs:
        # Check if function body contains a call to itself
        func_pattern = rf'^def\s+{re.escape(func_name)}\s*\([^)]*\):(.+?)(?=^def\s|\Z)'
        match = re.search(func_pattern, content, re.MULTILINE | re.DOTALL)
        if match:
            body = match.group(1)
            # Look for direct recursive call
            if re.search(rf'\b{re.escape(func_name)}\s*\(', body):
                print(
                    f"REQUIRED FOLLOW-UP: {file_path}:{func_name} contains recursion. "
                    f"BEFORE continuing: confirm depth-safety (base case + depth limit OR proof of O(log n) depth OR iterative alternative). "
                    f"Do not stop until you have confirmed this recursion is bounded for production inputs. "
                    f"Python's default stack limit is ~1000 frames.",
                    file=sys.stderr
                )
                return 2

    return 0

if __name__ == "__main__":
    sys.exit(main())

import json, sys, subprocess, os

def main():
    try:
        ev = json.load(sys.stdin)
    except Exception:
        return 0

    tool = ev.get("tool_name", "")
    inp = ev.get("tool_input") or {}

    if tool != "Edit":
        return 0

    file_path = inp.get("file_path", "")
    if not file_path.endswith(".py"):
        return 0

    if not os.path.isfile(file_path):
        return 0

    # Run ruff format on the edited file
    try:
        subprocess.run(["ruff", "format", file_path],
                      capture_output=True, check=False)
    except Exception:
        pass

    # Run ruff check and surface issues
    try:
        result = subprocess.run(["ruff", "check", file_path],
                               capture_output=True, text=True, check=False)
        if result.returncode != 0 and result.stdout.strip():
            print(f"REQUIRED FOLLOW-UP: Ruff found issues in {file_path}:", file=sys.stderr)
            print(result.stdout, file=sys.stderr)
            print("Fix each issue before proceeding.", file=sys.stderr)
            return 2
    except Exception:
        pass

    return 0

if __name__ == "__main__":
    sys.exit(main())

